        function formatExamples(examplesStr) {
            if (!examplesStr) return '';
            return examplesStr.split(',').map(v => {
                const verb = v.trim();
                return `<a href="https://conjugator.reverso.net/conjugation-french-verb-${verb}.html" target="_blank" style="color: #4CAF50; text-decoration: underline;">${verb}</a>`;
            }).join(', ');
        }

        function showToast(message) {
            let toast = document.getElementById('toast-notification');
            if (!toast) {
                toast = document.createElement('div');
                toast.id = 'toast-notification';
                toast.style.cssText = 'position: fixed; bottom: 20px; right: 20px; background-color: #222; color: #fff; padding: 12px 24px; border-radius: 4px; box-shadow: 0 4px 10px rgba(0,0,0,0.5); z-index: 1000; font-size: 0.95em; transition: opacity 0.3s; opacity: 0; pointer-events: none; border-left: 4px solid #fdd835;';
                document.body.appendChild(toast);
            }
            toast.textContent = message;
            toast.style.opacity = '1';
            setTimeout(() => {
                toast.style.opacity = '0';
            }, 2500);
        }

        function copyAIPrompt(verb) {
            const prompt = `Réponds uniquement dans ce format exact, sans introduction ni conclusion.
Chaque phrase d'exemple doit inclure une expression temporelle naturelle et appropriée au temps utilisé (ex. : "hier", "tous les jours", "demain", "autrefois", "en ce moment", etc.).

${verb}, v. <définition courte en français> (*<traductions anglaises courtes, ex. : inform, notify, warn>*)

PRES: <phrase d'exemple au présent>
IMPE: <phrase d'exemple à l'imparfait>
PRPE: <phrase d'exemple au passé composé>
SIMP: <phrase d'exemple au passé simple>
FUTU: <phrase d'exemple au futur>
COND: <phrase d'exemple au conditionnel>
PRSU: <phrase d'exemple au subjonctif présent>
IMSU: <phrase d'exemple au subjonctif imparfait>
IPER: <phrase d'exemple à l'impératif>
PRPA: <phrase d'exemple au participe présent>`;
            
            navigator.clipboard.writeText(prompt).then(() => {
                showToast(`Prompt IA copié pour ${verb} !`);
            }).catch(err => {
                console.error('Erreur de copie :', err);
            });
        }

        function getLawlessFrenchUrl(verb) {
            let cleanVerb = verb.toLowerCase().trim()
                .replace(/^(s’|s'|se\s+)/g, '')
                .normalize("NFD")
                .replace(/[\u0300-\u036f]/g, "")
                .replace(/\s+/g, '-');
            return `https://www.lawlessfrench.com/verb-conjugations/${cleanVerb}/`;
        }

        function formatSimilarVerbs(examplesStr, isYellow) {
            if (!examplesStr) return '';
            let itemsHtml = examplesStr.split(',').map(v => {
                const verb = v.trim();
                const wordColor = '#fdd835';
                const reversoUrl = `https://conjugator.reverso.net/conjugation-french-verb-${verb}.html`;
                const lawlessUrl = getLawlessFrenchUrl(verb);
                return `<div class="similar-verb-item">
                            <span style="color: ${wordColor}; font-weight: normal;">${verb}</span>
                            <div style="display: flex; gap: 6px;">
                                <a href="${lawlessUrl}" target="_blank" style="text-decoration: none; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle; transition: opacity 0.2s; opacity: 0.65;" onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='0.65'"><img src="https://www.lawlessfrench.com/favicon.ico" width="16" height="16" style="display: block; border-radius: 3px;" /></a>
                                <a href="${reversoUrl}" target="_blank" style="text-decoration: none; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle; transition: opacity 0.2s; opacity: 0.65;" onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='0.65'"><img src="https://cdn.reverso.net/conj/v2550/IMG/ReversoFavicon.ico" width="16" height="16" style="display: block; border-radius: 2px;" /></a>
                                <a href="javascript:void(0)" onclick="copyAIPrompt('${verb}')" title="Copier le prompt IA pour ${verb}" style="text-decoration: none; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle; transition: opacity 0.2s; opacity: 0.65;" onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='0.65'"><svg viewBox="0 0 16 16" width="16" height="16" style="display: block;"><rect x="0" y="0" width="16" height="16" rx="3" fill="#ffffff"/><text x="8" y="8" dominant-baseline="central" text-anchor="middle" font-family="'Inter', 'Outfit', system-ui, sans-serif" font-weight="800" font-size="7.5" fill="#1a1a1a" letter-spacing="0.3px">AI</text></svg></a>
                            </div>
                        </div>`;
            }).join('');
            return `<div class="similar-verbs-grid">${itemsHtml}</div>`;
        }

        const tenseNames = {
            "PRES": "présent",
            "IMPE": "imparfait",
            "PRPE": "passé composé",
            "SIMP": "passé&nbsp;simple",
            "FUTU": "futur",
            "COND": "conditionnel",
            "PRSU": "présent&nbsp;du subjonctif",
            "IMSU": "imparfait&nbsp;du subjonctif",
            "IPER": "impératif",
            "PRPA": "participe&nbsp;présent"
        };

        function renderConjugations(conj, verbName = null, showVal = true, alwaysShowTooltip = false, groupId = null) {
            if (!conj) return '';
            let html = '<div class="card">';
            if (verbName) {
                const reversoUrl = `https://conjugator.reverso.net/conjugation-french-verb-${verbName}.html`;
                const lawlessUrl = getLawlessFrenchUrl(verbName);
                html += `<div style="grid-column: 1 / -1; margin-bottom: 8px; font-size: 0.9em; display: flex; flex-direction: column; gap: 6px; color: #888;" class="prompt-instructions">`;
                html += `  <div style="display: flex; align-items: center;">`;
                html += `    Vérification croisée de la conjugaison du verbe <span style="color: #fdd835; margin-left: 4px; margin-right: 4px;">${verbName}</span> : `;
                html += `    <a href="${lawlessUrl}" target="_blank" style="text-decoration: none; margin-left: 6px; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle; transition: opacity 0.2s; opacity: 0.65;" onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='0.65'"><img src="https://www.lawlessfrench.com/favicon.ico" width="16" height="16" style="display: block; border-radius: 3px;" /></a>`;
                html += `    <a href="${reversoUrl}" target="_blank" style="text-decoration: none; margin-left: 4px; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle; transition: opacity 0.2s; opacity: 0.65;" onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='0.65'"><img src="https://cdn.reverso.net/conj/v2550/IMG/ReversoFavicon.ico" width="16" height="16" style="display: block; border-radius: 2px;" /></a>`;
                html += `  </div>`;
                html += `  <div style="display: flex; align-items: center;">`;
                html += `    Copier le prompt IA pour générer des exemples de <span style="color: #fdd835; margin-left: 4px; margin-right: 4px;">${verbName}</span> : `;
                html += `    <a href="javascript:void(0)" onclick="copyAIPrompt('${verbName}')" title="Copier le prompt IA pour ${verbName}" style="text-decoration: none; margin-left: 6px; display: inline-flex; align-items: center; justify-content: center; vertical-align: middle; transition: opacity 0.2s; opacity: 0.65;" onmouseover="this.style.opacity='1'" onmouseout="this.style.opacity='0.65'"><svg viewBox="0 0 16 16" width="16" height="16" style="display: block;"><rect x="0" y="0" width="16" height="16" rx="3" fill="#ffffff"/><text x="8" y="8" dominant-baseline="central" text-anchor="middle" font-family="'Inter', 'Outfit', system-ui, sans-serif" font-weight="800" font-size="7.5" fill="#1a1a1a" letter-spacing="0.3px">AI</text></svg></a>`;
                html += `  </div>`;
                html += `</div>`;
            }
            for (const [tense, info] of Object.entries(conj)) {
                const cls = info.reg ? 'reg' : 'irreg';
                const fullName = tenseNames[tense] || '';
                 html += `<div class="conjugation-row" data-tense="${tense}">
                            <span class="tense-label"><span class="tense-text">${tense}</span></span>
                            <div style="display: flex; flex-direction: column;">
                                ${showVal && info.val ? `<span class="${cls}">${info.val}</span>` : ""}`;
                let baseRule = info.base_rule;
                if (tense === 'PRPE' && groupId) {
                    if (groupId.startsWith('g1')) baseRule = '-é';
                    else if (groupId.startsWith('g2')) baseRule = '-i';
                    else if (groupId.startsWith('g3')) baseRule = '-u';
                }
                if (baseRule) {
                    const margin = (showVal && info.val) ? 'margin-top: 2px;' : 'margin-top: -2px;';
                    html += `   <span class="base-rule-text" data-rule="${baseRule}" data-name="${fullName}" data-group="${groupId}" style="color: #bbbbbb; font-size: 0.9em; font-style: italic; ${margin}">${baseRule}</span>`;
                }
                html += `   </div>
                         </div>`;
            }
            html += '</div>';
            return html;
        }

        function renderGroup(g) {
            const content = document.getElementById('main-content');
            let html = `<h2>${g.name}</h2>`;
            if (g.verb_count) {
                html += `<div style="background-color: rgba(255,255,255,0.03); padding: 12px 15px; border-radius: 6px; margin-bottom: 20px; border-left: 3px solid #64b5f6; font-size: 0.95em;">`;
                html += `<div><strong>Taille du groupe :</strong> ${g.verb_count}</div>`;
                html += `</div>`;
            }
            if (g.description) html += `<p class="group-description" style="font-size: 1.1em; color: #b0bec5; margin-bottom: 20px;">${g.description}</p>`;
            
            if (g.verbs && g.verbs.length > 0) {
                html += `<div class="verb-tabs" style="display: flex; gap: 5px; margin-bottom: 20px; border-bottom: 1px solid #333; padding-bottom: 0;">`;
                g.verbs.forEach((v, index) => {
                    const activeStyle = index === 0 ? 'background-color: rgba(253, 216, 53, 0.08); border-top-left-radius: 4px; border-top-right-radius: 4px; border-bottom: 2px solid transparent; color: #fdd835; font-weight: normal;' : 'background-color: transparent; border-top-left-radius: 4px; border-top-right-radius: 4px; border-bottom: 2px solid transparent; color: rgba(253, 216, 53, 0.6); font-weight: normal;';
                    html += `<button class="verb-tab-btn" onclick="selectVerbTab('${g.id}', '${v.name}', this)" style="border: none; font-size: 1.05em; cursor: pointer; padding: 8px 16px; transition: all 0.2s; ${activeStyle}">${v.name}</button>`;
                });
                html += `</div>`;
                
                html += `<div id="active-verb-conjugation">`;
                html += renderConjugations(g.verbs[0].conjugations, g.verbs[0].name, true, false, g.id);
                html += `</div>`;
            } else if (g.conjugations) {
                html += `<h3>Conjugaisons</h3>`;
                html += `<div id="active-verb-conjugation">`;
                html += renderConjugations(g.conjugations, null, true, false, g.id);
                html += `</div>`;
            }
            
            if (g.similar_verbs) {
                const label = g.id === 'g1' ? 'Vérification croisée de verbes similaires :' : 'Verbes similaires :';
                html += `<div class="similar-verbs-container" style="margin-top: 30px; padding-top: 15px; border-top: 1px solid #333; font-size: 0.95em;">`;
                html += `<strong>${label}</strong> ${formatSimilarVerbs(g.similar_verbs, g.id === 'g1')}`;
                html += `</div>`;
            }
            
            content.innerHTML = html;
        }

        function getSubgroupDescription(sg) {
            if (sg.id === 'g1_1') {
                return "Ce sont des verbes réguliers qui se conjuguent selon les règles générales des verbes en <span style='color: #fdd835; font-weight: bold;'>-er</span>.";
            }
            if (sg.id === 'g1_2' || sg.id === 'g1_3' || sg.id === 'g1_4' || sg.id === 'g1_5' || sg.id === 'g1_6' || sg.id === 'g1_7') {
                return "Ce sont des <span style='color: #cc7777;'>verbes irréguliers</span> qui se conjuguent comme les verbes en <span style='color: #fdd835; font-weight: bold;'>-er</span> avec des exceptions signalées ci-dessous en <span style='color: #cc7777;'>rouge</span>.";
            }
            if (sg.id === 'g2_1') {
                return "Ce sont des verbes réguliers qui se conjuguent selon les règles générales des verbes en <span style='color: #fdd835; font-weight: bold;'>-ir</span>.";
            }
            if (sg.id === 'g3_1') {
                return "Ce sont des verbes réguliers qui se conjuguent selon les règles générales des verbes en <span style='color: #fdd835; font-weight: bold;'>-re</span>.";
            }
            if (sg.id === 'g3_2' || sg.id === 'g3_3' || sg.id === 'g3_13' || sg.id === 'g3_18') {
                return "Ce sont des <span style='color: #cc7777;'>verbes irréguliers</span> qui se conjuguent comme les verbes en <span style='color: #fdd835; font-weight: bold;'>-ir</span> avec des exceptions signalées ci-dessous en <span style='color: #cc7777;'>rouge</span>.";
            }
            if (sg.id === 'g3_4' || sg.id === 'g3_5' || sg.id === 'g3_6' || sg.id === 'g3_65' || sg.id === 'g3_12' || sg.id === 'g3_14' || sg.id === 'g3_17' || sg.id === 'g3_16') {
                return "Ce sont des <span style='color: #cc7777;'>verbes irréguliers</span> qui se conjuguent comme les verbes en <span style='color: #fdd835; font-weight: bold;'>-re</span> avec des exceptions signalées ci-dessous en <span style='color: #cc7777;'>rouge</span>.";
            }
            if (sg.id === 'g3_7') {
                return "Ce sont des <span style='color: #cc7777;'>verbes irréguliers</span> qui se conjuguent comme les verbes en <span style='color: #fdd835; font-weight: bold;'>-re</span> ou <span style='color: #fdd835; font-weight: bold;'>-oir</span> avec des exceptions signalées ci-dessous en <span style='color: #cc7777;'>rouge</span>.";
            }
            if (sg.id === 'g3_8') {
                return "Ce sont des <span style='color: #cc7777;'>verbes irréguliers</span> qui se conjuguent comme les verbes en <span style='color: #fdd835; font-weight: bold;'>-er</span> avec des exceptions signalées ci-dessous en <span style='color: #cc7777;'>rouge</span>.";
            }
            if (sg.id === 'g3_9') {
                return "Ce sont des <span style='color: #cc7777;'>verbes hautement irréguliers</span> avec des formes spécifiques signalées ci-dessous en <span style='color: #cc7777;'>rouge</span>.";
            }
            return "Ce sont des <span style='color: #cc7777;'>verbes irréguliers</span> avec des exceptions signalées ci-dessous en <span style='color: #cc7777;'>rouge</span>.";
        }

        function renderSubgroup(sg, parentName) {
            const content = document.getElementById('main-content');
            const isRegular = (sg.id === 'g1_1' || sg.id === 'g2_1' || sg.id === 'g3_1');
            const numClass = isRegular ? 'group-num regular-num' : 'group-num irregular-num';
            let sgName = sg.name.replace("class='group-num'", `class='${numClass}'`);
            let html = `
            <div class="subgroup-header-container" style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;">
                <h2 style="margin: 0;">${sgName}</h2>
                <span class="help-icon" style="cursor: pointer; color: #ffffff; font-size: 1.1em; display: flex; align-items: center; justify-content: center; width: 22px; height: 22px; border: 2px solid #ffffff; border-radius: 50%; font-weight: normal; user-select: none; flex-shrink: 0;">?</span>
            </div>`;
            const desc = getSubgroupDescription(sg);
            const borderColor = isRegular ? '#90caf9' : '#cc7777';
            html += `<div class="subgroup-description" style="background-color: rgba(255,255,255,0.03); padding: 12px 15px; border-radius: 6px; margin-bottom: 20px; border-left: 3px solid ${borderColor}; font-size: 0.95em;">`;
            html += `<div>${desc}</div>`;
            html += `</div>`;
            if (sg.examples && sg.id !== 'g3_2') html += `<p><strong>Exemples :</strong> ${formatExamples(sg.examples)}</p>`;
            if (sg.note) html += `<p><em>${sg.note}</em></p>`;
            
            if (sg.verbs && sg.verbs.length > 0) {
                html += `<div class="verb-tabs" style="display: flex; gap: 5px; margin-bottom: 20px; border-bottom: 1px solid #333; padding-bottom: 0;">`;
                sg.verbs.forEach((v, index) => {
                    const activeStyle = index === 0 ? 'background-color: rgba(253, 216, 53, 0.08); border-top-left-radius: 4px; border-top-right-radius: 4px; border-bottom: 2px solid transparent; color: #fdd835; font-weight: normal;' : 'background-color: transparent; border-top-left-radius: 4px; border-top-right-radius: 4px; border-bottom: 2px solid transparent; color: rgba(253, 216, 53, 0.6); font-weight: normal;';
                    html += `<button class="verb-tab-btn" onclick="selectVerbTab('${sg.id}', '${v.name}', this)" style="border: none; font-size: 1.05em; cursor: pointer; padding: 8px 16px; transition: all 0.2s; ${activeStyle}">${v.name}</button>`;
                });
                html += `</div>`;
                
                html += `<div id="active-verb-conjugation">`;
                html += renderConjugations(sg.verbs[0].conjugations, sg.verbs[0].name, true, false, sg.id);
                html += `</div>`;
            } else if (sg.conjugations) {
                html += `<h3>Conjugaisons</h3>`;
                html += `<div id="active-verb-conjugation">`;
                html += renderConjugations(sg.conjugations, null, true, false, sg.id);
                html += `</div>`;
            }
            
            if (sg.similar_verbs) {
                let label = 'verbes similaires :';
                if (sg.id === 'g3_14') {
                    label = 'Verbes dérivés des verbes ci-dessus :';
                }
                const tabVerbs = (sg.verbs || []).map(v => v.name.toLowerCase().trim());
                const cleanSimilar = sg.similar_verbs.split(',')
                    .map(v => v.trim())
                    .filter((v, idx, self) => v && self.indexOf(v) === idx && !tabVerbs.includes(v.toLowerCase()));
                if (cleanSimilar.length > 0) {
                    html += `<div class="similar-verbs-container" style="margin-top: 30px; padding-top: 15px; border-top: 1px solid #333; font-size: 0.95em;">`;
                    html += `<strong>${label}</strong> ${formatSimilarVerbs(cleanSimilar.join(', '), sg.id === 'g3_2')}`;
                    html += `</div>`;
                }
            }
            
            content.innerHTML = html;
        }

        function selectVerbTab(groupId, verbName, btnElement) {
            let targetGroupOrSubgroup = null;
            for (let g of data.groups) {
                if (g.id === groupId) {
                    targetGroupOrSubgroup = g;
                    break;
                }
                if (g.subgroups) {
                    targetGroupOrSubgroup = g.subgroups.find(s => s.id === groupId);
                    if (targetGroupOrSubgroup) break;
                }
            }
            if (!targetGroupOrSubgroup) return;
            
            const verb = targetGroupOrSubgroup.verbs.find(v => v.name === verbName);
            if (!verb) return;
            
            const tabContainer = btnElement.parentElement;
            tabContainer.querySelectorAll('.verb-tab-btn').forEach(btn => {
                btn.style.color = 'rgba(253, 216, 53, 0.6)';
                btn.style.fontWeight = 'normal';
                btn.style.backgroundColor = 'transparent';
                btn.style.borderBottom = '2px solid transparent';
            });
            btnElement.style.color = '#fdd835';
            btnElement.style.fontWeight = 'normal';
            btnElement.style.backgroundColor = 'rgba(253, 216, 53, 0.08)';
            btnElement.style.borderBottom = '2px solid transparent';
            
            document.getElementById('active-verb-conjugation').innerHTML = renderConjugations(verb.conjugations, verb.name, true, false, groupId);
        }

                function getSuffixConjugations(verbName, patternId, stemToReplace) {
            const conj = generateConjugations(verbName, patternId);
            const res = {};
            for (const [tense, info] of Object.entries(conj)) {
                let val = info.val;
                val = val.replaceAll(`<span class="reg-part">${stemToReplace}</span>`, `<span class="reg-part">-</span>`);
                val = val.replaceAll(`<span class="reg-part">${stemToReplace}iss</span>`, `<span class="reg-part">-iss</span>`);
                val = val.replaceAll(`<span class="reg-part">${stemToReplace}d</span>`, `<span class="reg-part">-d</span>`);
                val = val.replaceAll(`<span class="reg-part">${stemToReplace}t</span>`, `<span class="reg-part">-t</span>`);
                if (patternId === 'g1') {
                    val = val.replaceAll(`<span class="reg-part">aimer</span>`, `<span class="reg-part">-er</span>`);
                } else if (patternId === 'g2') {
                    val = val.replaceAll(`<span class="reg-part">finir</span>`, `<span class="reg-part">-ir</span>`);
                } else if (patternId === 'g3_1') {
                    val = val.replaceAll(`<span class="reg-part">vendr</span>`, `<span class="reg-part">-r</span>`);
                }
                let baseRule = info.base_rule;
                if (tense === 'PRPE') {
                    if (patternId.startsWith('g1')) baseRule = '-é';
                    else if (patternId.startsWith('g2')) baseRule = '-i';
                    else if (patternId.startsWith('g3')) baseRule = '-u';
                }
                res[tense] = { val: val, base_rule: baseRule, reg: info.reg };
            }
            return res;
        }

        
